        fm_text = yaml.dump(frontmatter, default_flow_style=False, allow_unicode=True).strip()
        parts.append(f"---\n{fm_text}\n---\n")

    gap_map = {}
    for text, pos in gaps:
        gap_map.setdefault(pos, []).append(text)

