"""
VERL training log monitor for rllm-monitor.

Usage:
    python rllm_train/monitor_agent_verl.py stream <log_path>
    python rllm_train/monitor_agent_verl.py oneshot <log_path> [--last N]

Handles VERL's Ray worker + Tracking console output format.
"""

import os
import re
import sys
import time

# VERL-specific log patterns
_VERL_METRIC_RE = re.compile(
    r"(agent_grpo|critic|actor|perf|val-core|training)/(\S+)\s*[:=]\s*(\S+)"
)
_STEP_RE = re.compile(r"(?:step|global_step)\s*[:=]\s*(\d+)", re.I)
_EPOCH_RE = re.compile(r"epoch\s*[:=]\s*([\d.]+)", re.I)
_SCORE_RE = re.compile(r"(?:score|rewards)/mean\s*[:=]\s*([\d.-]+)")
_GRAD_RE = re.compile(r"grad_norm\s*[:=]\s*([\d.-]+)")
_LOSS_RE = re.compile(r"(?:pg_loss|policy_loss)\s*[:=]\s*([\d.-]+)")
_THROUGHPUT_RE = re.compile(r"(?:throughput|tokens_per_second)\s*[:=]\s*([\d.-]+)")
_ERROR_RE = re.compile(r"Traceback|(?<!\w)Error(?!\w)|OOM|out of memory|Killed|SIGTERM|SIGKILL", re.I)
_COMPLETE_RE = re.compile(r"Training (?:completed|finished)", re.I)
_RAY_ACTOR_DIED_RE = re.compile(r"Actor died|RayActorError", re.I)


def _emit(line: str) -> None:
    print(line, flush=True)


def _extract_step_num(line: str) -> int | None:
    m = _STEP_RE.search(line)
    return int(m.group(1)) if m else None


def _extract_metric(line: str) -> dict | None:
    """Extract VERL metric from a log line. Returns dict or None."""
    m = _VERL_METRIC_RE.search(line)
    if not m:
        return None
    category = m.group(1)
    key = m.group(2)
    try:
        value = float(m.group(3))
    except ValueError:
        value = m.group(3)
    return {"category": category, "key": key, "value": value, "full": f"{category}/{key}"}


def _format_verl_step(line: str, step_num: int) -> str:
    """Format a VERL metric line as a monitor step line."""
    parts = []
    # Extract key metrics from this line or track state
    score_m = _SCORE_RE.search(line)
    grad_m = _GRAD_RE.search(line)
    loss_m = _LOSS_RE.search(line)
    tp_m = _THROUGHPUT_RE.search(line)

    if score_m:
        parts.append(f"R {float(score_m.group(1)):.4f}")
    if grad_m:
        parts.append(f"Grad {float(grad_m.group(1)):.4f}")
    if loss_m:
        parts.append(f"Loss {float(loss_m.group(1)):.4f}")
    if tp_m:
        parts.append(f"tok/s {float(tp_m.group(1)):.1f}")

    if not parts:
        # Generic metric line
        m = _VERL_METRIC_RE.search(line)
        if m:
            return f"VERL Step {step_num} | {m.group(1)}/{m.group(2)}={m.group(3)}"
        return f"VERL Step {step_num} | {line.strip()[:120]}"

    return f"VERL Step {step_num} | {' | '.join(parts)}"


def _handle_line(line: str, seen_steps: set[int], state: dict) -> str | None:
    """Process one VERL log line. Updates state dict with latest metrics.
    Returns 'step'|'report'|'error'|None.
    """
    # Check for completion
    if _COMPLETE_RE.search(line):
        _emit(line.strip())
        return "report"

    # Check for Ray actor death
    if _RAY_ACTOR_DIED_RE.search(line):
        _emit(f"ERROR: {line.strip()[:200]}")
        return "error"

    # Check for errors (exclude benign INFO/WARNING lines)
    if _ERROR_RE.search(line):
        # Skip if it's a warning (not a real error)
        if not re.search(r"WARNING|UserWarning|FutureWarning|Deprecated", line):
            _emit(f"ERROR: {line.strip()[:200]}")
            return "error"

    # Check for step progress
    step_num = _extract_step_num(line)
    metric = _extract_metric(line)

    if step_num is not None:
        if step_num > state.get("last_step", 0):
            state["last_step"] = step_num
            # Aggregate metrics that arrived since last step change
            output = _format_verl_step(line, step_num)
            if step_num not in seen_steps:
                seen_steps.add(step_num)
                _emit(output)
                return "step"
            elif metric:
                # Same step, new metric - emit as detail
                _emit(f"  {metric['full']}={metric['value']}")
                return "detail"

    # Track metrics even without step change
    if metric:
        state.setdefault("metrics", {})[metric["full"]] = metric["value"]

    return None


def stream(log_path: str, timeout: int = 3600) -> None:
    """Persistent streaming mode for VERL training log."""
    seen_steps: set[int] = set()
    state: dict = {"last_step": 0}
    start = time.time()
    inode: int | None = None

    while not os.path.exists(log_path):
        if time.time() - start > 120:
            _emit(f"TIMEOUT: log file {log_path} did not appear within 120s")
            return
        time.sleep(2)

    try:
        st = os.stat(log_path)
        inode = st.st_ino
        pos = st.st_size
    except OSError:
        pos = 0

    last_data_time = time.time()

    while True:
        if time.time() - start > timeout:
            _emit("TIMEOUT: monitor stream exceeded time limit")
            return

        try:
            st = os.stat(log_path)
            current_inode = st.st_ino
            current_size = st.st_size
        except OSError:
            time.sleep(2)
            continue

        if current_inode != inode or current_size < pos:
            inode = current_inode
            pos = 0
            seen_steps.clear()
            state["last_step"] = 0

        if current_size > pos:
            last_data_time = time.time()
            try:
                with open(log_path, "r", errors="replace") as f:
                    f.seek(pos)
                    data = f.read()
                    pos = f.tell()
            except (OSError, ValueError):
                time.sleep(2)
                continue

            for line in data.splitlines():
                result = _handle_line(line, seen_steps, state)
                if result in ("report", "error"):
                    return
        else:
            if time.time() - last_data_time > 600:
                _emit("WARN: no log output for 10 minutes, training may be stalled")

        time.sleep(2)


def oneshot(log_path: str, last_n: int = 1) -> None:
    """One-shot mode: print recent VERL metrics. For CronCreate fallback."""
    if not os.path.exists(log_path):
        _emit("ONESHOT: log file not found")
        return

    try:
        with open(log_path, "r", errors="replace") as f:
            lines = f.readlines()
    except OSError:
        _emit("ONESHOT: cannot read log file")
        return

    # Check for terminal events first
    for line in lines:
        if _COMPLETE_RE.search(line):
            _emit("DETECTED: Training completed")
            return
        if _RAY_ACTOR_DIED_RE.search(line):
            _emit(f"DETECTED: {line.strip()[:200]}")
            return
        if _ERROR_RE.search(line) and not re.search(r"WARNING|UserWarning|FutureWarning|Deprecated", line):
            _emit(f"DETECTED: {line.strip()[:200]}")
            return

    # Extract step progress
    step_lines = []
    last_step = 0
    for line in lines:
        sn = _extract_step_num(line)
        if sn is not None and sn != last_step:
            last_step = sn
            step_lines.append((sn, line))

    if step_lines:
        for sn, line in step_lines[-last_n:]:
            _emit(_format_verl_step(line, sn))
    else:
        # Show recent metric lines
        metric_lines = [l for l in lines if _VERL_METRIC_RE.search(l)]
        if metric_lines:
            for l in metric_lines[-min(last_n * 3, 5):]:
                _emit(f"PROGRESS: {l.strip()[:200]}")
        else:
            for l in reversed(lines):
                stripped = l.strip()
                if stripped and not stripped.startswith("[transformers]"):
                    _emit(f"PROGRESS: {stripped[:200]}")
                    break
            else:
                _emit("PROGRESS: log exists but no recognizable content yet")


if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser(description="VERL training log monitor")
    sub = parser.add_subparsers(dest="mode")

    p_stream = sub.add_parser("stream")
    p_stream.add_argument("log_path")
    p_stream.add_argument("--timeout", type=int, default=3600)

    p_shot = sub.add_parser("oneshot")
    p_shot.add_argument("log_path")
    p_shot.add_argument("--last", type=int, default=1)

    args = parser.parse_args()
    if args.mode == "stream":
        stream(args.log_path, timeout=args.timeout)
    elif args.mode == "oneshot":
        oneshot(args.log_path, last_n=args.last)
    else:
        parser.print_help()
        sys.exit(1)

